#include <meta>
#include <iostream>
#include <string_view>

enum class Color { Red, Green, Blue };

int main() {
    // enumerators_of возвращает диапазон std::meta::info
    // template for — единственный способ итерировать consteval-only тип
    template for (constexpr auto e :
                  std::define_static_array(std::meta::enumerators_of(^^Color))) {
        std::cout << std::meta::identifier_of(e) << "\n";
    }
}

#include <meta>
#include <iostream>
#include <string_view>

enum class Direction { North, South, East, West };

std::string_view to_string(Direction d) {
    template for (constexpr auto e :
                  std::define_static_array(std::meta::enumerators_of(^^Direction))) {
        if ([:e:] == d) return std::meta::identifier_of(e);
    }
    return "unknown";
}

int main() {
    std::cout << to_string(Direction::North) << "\n";
    std::cout << to_string(Direction::East)  << "\n";
    std::cout << to_string(Direction::South) << "\n";
    std::cout << to_string(Direction::West)  << "\n";

    Direction d = Direction::West;
    std::cout << "Runtime: " << to_string(d) << "\n";
}

#include <meta>
#include <iostream>
#include <string_view>
#include <optional>

