#include <meta>
#include <print>

struct Config {
    int width;
    int height;
    float scale;
};

template <class T>
void diff(const T& a, const T& b) {
    template for (constexpr auto m : std::define_static_array(
            std::meta::nonstatic_data_members_of(^^T,
                std::meta::access_context::unchecked()))) {
        if (a.[: m :] != b.[: m :]) {
            std::println("{}: {} -> {}",
                std::meta::identifier_of(m),
                a.[: m :],
                b.[: m :]);
        }
    }
}

int main() {
    Config c1{1920, 1080, 1.0f};
    Config c2{1280, 1080, 1.5f};
    diff(c1, c2);
}
